import torch, wandb
from transformers import TrainerCallback

class GradNormCallback(TrainerCallback):
    """Log gradient norm per step and alert on large values."""
    def on_step_end(self, args, state, control, model=None, **kwargs):
        if state.global_step % args.logging_steps != 0:
            return
        total_norm = 0.0
        for param in model.parameters():
            if param.grad is not None:
                total_norm += param.grad.data.norm(2).item() ** 2
        total_norm = total_norm ** 0.5
        if wandb.run:
            wandb.log({"train/grad_norm": total_norm}, step=state.global_step)
        if total_norm > 10.0:
            print(f"WARNING: large grad norm {total_norm:.2f} at step {state.global_step}")

# Attach to Trainer
from transformers import Trainer
trainer = Trainer(
    model=model,
    args=args,
    train_dataset=packed_ds,
    callbacks=[GradNormCallback()],
)
